import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (request: ZuploRequest, context: ZuploContext) {
  const country = request.headers.get("cf-ipcountry");

  let upstreamUrl: string;
  if (country === "US") {
    upstreamUrl = "https://echo.zuplo.io/us";
  } else {
    upstreamUrl = "https://echo.zuplo.io/default";
  }

  const response = await fetch(upstreamUrl);
  return response;
}

{
  "openapi": "3.1.0",
  "info": {
    "version": "1.0.0",
    "title": "Dynamic Upstream Routing API",
    "description": "An API that routes requests to different upstream backends based on the client's country."
  },
  "paths": {
    "/api/data": {
      "get": {
        "summary": "Get data from country-specific upstream",
        "description": "Proxies the request to a different backend based on the cf-ipcountry header. Routes to https://echo.zuplo.io/us for US, otherwise to https://echo.zuplo.io/default.",
        "operationId": "get-data",
        "x-zuplo-route": {
          "corsPolicy": "none",
          "handler": {
            "export": "default",
            "module": "$import(./modules/routing.ts)"
          }
        },
        "responses": {
          "200": {
            "description": "Successful response from the proxied upstream"
          }
        }
      }
    }
  }
}

